<?php
declare(strict_types=1);
require_once __DIR__.'/_layout.php';require_once dirname(__DIR__,2).'/includes/academico_flujo.php';$pdo=obtenerConexion();$docenteId=(int)$GLOBALS['docentePortalId'];docenteCabecera('Entregas y notas','entregas','Revisión por capacitación, sección, contenido y estado.');docenteSelectorSupervision($pdo);$curso=docenteId($_GET['curso']??0);$seccion=docenteId($_GET['seccion']??0);$contenido=docenteId($_GET['contenido']??0);$estado=in_array($_GET['estado']??'', ['enviada','en_revision','aprobada','rechazada','requiere_correccion'],true)?$_GET['estado']:'';$where=['c.docente_id=:d','s.docente_id=:d2'];$pa=['d'=>$docenteId,'d2'=>$docenteId];if($curso){$where[]='e.asignatura_id=:a';$pa['a']=$curso;}if($seccion){if(!docentePoseeSeccion($pdo,$docenteId,$seccion)){http_response_code(403);exit('Sección no autorizada.');}$where[]='e.seccion_id=:s';$pa['s']=$seccion;}if($contenido){$where[]='e.contenido_id=:c';$pa['c']=$contenido;}if($estado){$where[]='e.estado=:estado';$pa['estado']=$estado;}$q=$pdo->prepare('SELECT e.*,c.titulo contenido,c.tipo,a.nombre capacitacion,s.codigo seccion,u.nombre,u.apellido,(SELECT COUNT(*) FROM entrega_evidencias ev WHERE ev.entrega_id=e.id) evidencias FROM entregas_contenido e JOIN contenidos c ON c.id=e.contenido_id JOIN asignaturas a ON a.id=e.asignatura_id JOIN capacitacion_secciones s ON s.id=e.seccion_id JOIN usuarios u ON u.id=e.estudiante_id WHERE '.implode(' AND ',$where).' ORDER BY e.enviado_at DESC LIMIT 200');$q->execute($pa);$filas=$q->fetchAll();$q=$pdo->prepare("SELECT s.id,s.codigo,a.id asignatura_id,a.nombre capacitacion FROM capacitacion_secciones s JOIN asignaturas a ON a.id=s.asignatura_id WHERE s.docente_id=:d ORDER BY a.nombre,s.codigo");$q->execute(['d'=>$docenteId]);$secciones=$q->fetchAll();$q=$pdo->prepare('SELECT id,titulo,seccion_id FROM contenidos WHERE docente_id=:d ORDER BY titulo');$q->execute(['d'=>$docenteId]);$contenidos=$q->fetchAll();
?><div class="card card-rounded mb-4"><div class="card-body"><form class="row g-2"><div class="col-md-3"><select class="form-select" name="curso"><option value="">Todas las capacitaciones</option><?php $vistos=[];foreach($secciones as$s):if(isset($vistos[$s['asignatura_id']]))continue;$vistos[$s['asignatura_id']]=1;?><option value="<?=$s['asignatura_id']?>" <?=$curso===$s['asignatura_id']?'selected':''?>><?=atenea_e($s['capacitacion'])?></option><?php endforeach;?></select></div><div class="col-md-3"><select class="form-select" name="seccion"><option value="">Todas las secciones</option><?php foreach($secciones as$s):?><option value="<?=$s['id']?>" <?=$seccion===$s['id']?'selected':''?>><?=atenea_e($s['capacitacion'].' · '.$s['codigo'])?></option><?php endforeach;?></select></div><div class="col-md-3"><select class="form-select" name="contenido"><option value="">Todos los contenidos</option><?php foreach($contenidos as$c):?><option value="<?=$c['id']?>" <?=$contenido===$c['id']?'selected':''?>><?=atenea_e($c['titulo'])?></option><?php endforeach;?></select></div><div class="col-md-2"><select class="form-select" name="estado"><option value="">Todos los estados</option><?php foreach(['enviada','en_revision','aprobada','rechazada','requiere_correccion'] as$e):?><option value="<?=$e?>" <?=$estado===$e?'selected':''?>><?=atenea_e($e)?></option><?php endforeach;?></select></div><div class="col-md-1"><button class="btn btn-primary w-100">Filtrar</button></div></form></div></div><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Estudiante</th><th>Contenido</th><th>Intento</th><th>Estado/nota</th><th>Evidencias</th><th></th></tr></thead><tbody><?php foreach($filas as$e):?><tr><td><?=atenea_e(trim($e['nombre'].' '.$e['apellido']))?></td><td><strong><?=atenea_e($e['contenido'])?></strong><small class="d-block"><?=atenea_e($e['capacitacion'].' · '.$e['seccion'])?></small></td><td><?=$e['intento']?><small class="d-block"><?=date('d/m/Y H:i',strtotime($e['enviado_at']))?></small></td><td><?=atenea_e($e['estado'])?><?php if($e['nota']!==null):?><br><strong><?=number_format((float)$e['nota'],2)?>/10</strong><?php endif;?></td><td><?php if($e['evidencias']):$qev=$pdo->prepare('SELECT id,archivo_nombre FROM entrega_evidencias WHERE entrega_id=:e');$qev->execute(['e'=>$e['id']]);foreach($qev->fetchAll() as$ev):?><a class="d-block" href="<?=atenea_url('src/academico/archivo.php?tipo=evidencia&id='.$ev['id'])?>"><?=atenea_e($ev['archivo_nombre'])?></a><?php endforeach;else:?>—<?php endif;?></td><td><button class="btn btn-sm btn-outline-primary" data-bs-toggle="collapse" data-bs-target="#review<?=$e['id']?>">Revisar</button></td></tr><tr class="collapse" id="review<?=$e['id']?>"><td colspan="6"><div class="p-3 bg-light"><p><strong>Comentario:</strong> <?=nl2br(atenea_e($e['comentario']))?></p><p><strong>Resultado:</strong> <?=nl2br(atenea_e($e['resultado']))?></p><form class="row g-2" method="post" action="entrega-revisar.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><input type="hidden" name="entrega_id" value="<?=$e['id']?>"><div class="col-md-3"><label class="form-label">Estado</label><select class="form-select" name="estado" required><?php foreach(['en_revision','aprobada','rechazada','requiere_correccion'] as$x):?><option value="<?=$x?>" <?=$e['estado']===$x?'selected':''?>><?=atenea_e($x)?></option><?php endforeach;?></select></div><div class="col-md-2"><label class="form-label">Nota 0–10</label><input class="form-control" type="number" name="nota" min="0" max="10" step="0.01" value="<?=atenea_e($e['nota'])?>"></div><div class="col-md-5"><label class="form-label">Retroalimentación</label><textarea class="form-control" name="retroalimentacion" maxlength="5000" required><?=atenea_e($e['retroalimentacion'])?></textarea></div><div class="col-md-2 d-flex align-items-end"><button class="btn btn-primary w-100">Guardar revisión</button></div></form></div></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5">No hay entregas con esos filtros.</td></tr><?php endif;?></tbody></table></div></div></div><?php docentePie();
